import java.io.File;
import java.io.FileNotFoundException;
import java.nio.file.Paths;
import java.util.Scanner;

public class SecureFileLoader {
    public static String loadFile(String filename) {
        try {
            // Define a base directory to prevent path traversal attacks
            String baseDir = "/path/to/secure/directory/";
            // Use Paths.get to normalize the path and prevent traversal
            File file = new File(Paths.get(baseDir, filename).toString());
            // Check if the file is within the base directory
            if (!file.getCanonicalPath().startsWith(baseDir)) {
                throw new SecurityException("Access denied");
            }
            Scanner scanner = new Scanner(file);
            return scanner.useDelimiter("\\Z").next();
        } catch (FileNotFoundException e) {
            return "File not found";
        } catch (SecurityException e) {
            return "Access denied";
        }
    }

    public static void main(String[] args) {
        System.out.println(loadFile("example.txt"));
    }
}
```

